mapper.select:
SELECT id, name, dataset_id, chart_type, x_field, y_field, group_field, created_at
FROM bi_chart
WHERE id = #{id}

mapper.update:
UPDATE bi_chart
SET name = #{name}, dataset_id = #{datasetId}, chart_type = #{chartType},
    x_field = #{xField}, y_field = #{yField}, group_field = #{groupField}
WHERE id = #{id}
